
.order-by {
    display: none;
    align-items: center;
    justify-content: center;
    padding: 10px 0 20px;
    gap: 5px;

    &.show {
        display: flex;
    }

    @media screen and (max-width: 768px) {
        padding: 15px 0 5px;
    }

    p {
        text-align: center;
        margin: 0;
        font-weight: 500;
        font-size: 16px;

        b {
            color: #ff4438;
            font-weight: 800;
        }

        @media screen and (max-width: 768px) {
            font-size: 14px;
        }
    }
}
